#include <stdint.h>
#include <stdio.h>
extern void initialise_monitor_handles(void);
void delay(void)
{
    for(volatile uint32_t i = 0; i < 300000; i++);
}

#if !defined(__SOFT_FP__) && defined(__ARM_FP)
#warning "FPU is not initialized, but the project is compiling for an FPU. Please initialize the FPU before use."
#endif

int main(void)
{
	initialise_monitor_handles();
    volatile uint32_t *RCC_APB2ENR = (uint32_t*)0x40021018;
    volatile uint32_t *GPIOA_CRH   = (uint32_t*)0x40010804;
    volatile uint32_t *GPIOB_CRH   = (uint32_t*)0x40010C04;
    volatile uint32_t *GPIOA_IDR   = (uint32_t*)0x40010808;
    volatile uint32_t *GPIOA_ODR   = (uint32_t*)0x4001080C;
    volatile uint32_t *GPIOB_ODR   = (uint32_t*)0x40010C0C;

    // Enable Clock for GPIOA and GPIOB
    *RCC_APB2ENR |= 0x0000000C;

    // Configure PA8-PA11 (Columns) as Input Pull-Up/Pull-Down
    *GPIOA_CRH &= 0xFFFF0000;

    // Configure PB12-PB15 (Rows) as Output Push-Pull @ 2MHz
    *GPIOB_CRH &= 0x0000FFFF;

    // PA11 PA10 PA9 PA8 = 1000 1000 1000 1000
    *GPIOA_CRH |= 0x00008888;

    // PB15 PB14 PB13 PB12 = 0010 0010 0010 0010
    *GPIOB_CRH |= 0x22220000;

    // Enable Internal Pull-Ups on PA8-PA11
    *GPIOA_ODR |= 0x00000F00;

    while(1)
    {
        // ROWS = HIGH (output)
        *GPIOB_ODR |= 0x0000F000;

        // make R1 = Low (R1 = PB12)
        *GPIOB_ODR &= ~(1<<12);

        //check the columns
        //check c1(PA8)
        if(!(*GPIOA_IDR & (1<<8)))
        {
            //key is pressed(its set to active HIGH by default when pressed it goes to ACTIVE LOW)
            delay();
            while(!(*GPIOA_IDR & (1<<8)));
            printf("1\n");
        }

        //check c2(PA9)
        if(!(*GPIOA_IDR & (1<<9)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<9)));
            printf("2\n");
        }

        //check c3(PA10)
        if(!(*GPIOA_IDR & (1<<10)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<10)));
            printf("3\n");
        }

        //check c4(PA11)
        if(!(*GPIOA_IDR & (1<<11)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<11)));
            printf("A\n");
        }

        // ROWS = HIGH (output)
        *GPIOB_ODR |= 0x0000F000;

        // make R2 = Low (R2 = PB13)
        *GPIOB_ODR &= ~(1<<13);

        //check the columns
        //check c1(PA8)
        if(!(*GPIOA_IDR & (1<<8)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<8)));
            printf("4\n");
        }

        //check c2(PA9)
        if(!(*GPIOA_IDR & (1<<9)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<9)));
            printf("5\n");
        }

        //check c3(PA10)
        if(!(*GPIOA_IDR & (1<<10)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<10)));
            printf("6\n");
        }

        //check c4(PA11)
        if(!(*GPIOA_IDR & (1<<11)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<11)));
            printf("B\n");
        }

        // ROWS = HIGH (output)
        *GPIOB_ODR |= 0x0000F000;

        // make R3 = Low (R3 = PB14)
        *GPIOB_ODR &= ~(1<<14);

        //check the columns
        //check c1(PA8)
        if(!(*GPIOA_IDR & (1<<8)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<8)));
            printf("7\n");
        }

        //check c2(PA9)
        if(!(*GPIOA_IDR & (1<<9)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<9)));
            printf("8\n");
        }

        //check c3(PA10)
        if(!(*GPIOA_IDR & (1<<10)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<10)));
            printf("9\n");
        }

        //check c4(PA11)
        if(!(*GPIOA_IDR & (1<<11)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<11)));
            printf("C\n");
        }

        // ROWS = HIGH (output)
        *GPIOB_ODR |= 0x0000F000;

        // make R4 = Low (R4 = PB15)
        *GPIOB_ODR &= ~(1<<15);

        //check the columns
        //check c1(PA8)
        if(!(*GPIOA_IDR & (1<<8)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<8)));
            printf("*\n");
        }

        //check c2(PA9)
        if(!(*GPIOA_IDR & (1<<9)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<9)));
            printf("0\n");
        }

        //check c3(PA10)
        if(!(*GPIOA_IDR & (1<<10)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<10)));
            printf("#\n");
        }

        //check c4(PA11)
        if(!(*GPIOA_IDR & (1<<11)))
        {
            delay();
            while(!(*GPIOA_IDR & (1<<11)));
            printf("D\n");
        }
    }

    /* Loop forever */
    for(;;);
}
